```cpp
common_chat_templates_ptr common_chat_templates_init(
    const struct llama_model * model,
    const std::string & chat_template_override,
    const std::string & bos_token_override,
    const std::string & eos_token_override) {

    // 1. Determine template source
    std::string default_template_src;
    if (!chat_template_override.empty()) {
        default_template_src = chat_template_override;
    } else if (model) {
        // Get from model metadata
        const auto * str = llama_model_chat_template(model, nullptr);
        if (str) default_template_src = str;
    }

    // 2. Apply workarounds for known broken templates
    // (Patches for bugs in specific model templates)

    // 3. Get BOS/EOS tokens
    if (model) {
        const auto * vocab = llama_model_get_vocab(model);
        token_bos = common_token_to_piece(vocab, llama_vocab_bos(vocab));
        token_eos = common_token_to_piece(vocab, llama_vocab_eos(vocab));
        add_bos = llama_vocab_get_add_bos(vocab);
        add_eos = llama_vocab_get_add_eos(vocab);
    }

    // 4. Compile templates
    common_chat_templates_ptr tmpls(new common_chat_templates());
    tmpls->template_default = std::make_unique<common_chat_template>(
        default_template_src, token_bos, token_eos);

    // 5. Load tool_use variant if available
    if (!template_tool_use_src.empty()) {
        tmpls->template_tool_use = std::make_unique<common_chat_template>(
            template_tool_use_src, token_bos, token_eos);
    }

    return tmpls;
}
